      "faulty statistics":                         { section:"reading", meaning:"thống kê sai sót, số liệu không đáng tin", type:"phrase", collocation:"based on faulty statistics", example:"Several influential reports on plastic pollution were later found to contain faulty statistics.", connotation:"negative" },
      "strikingly":                                { section:"reading", meaning:"đáng chú ý, nổi bật, một cách nổi trội", type:"adverb", collocation:"strikingly similar/different", example:"The concentration of microplastics was strikingly higher near densely populated coastlines.", connotation:"neutral" },
