      "bothersome":                                { section:"reading", meaning:"gây phiền toái, đáng lo ngại", type:"adjective", collocation:"considered bothersome but not fatal", example:"While plastic debris is bothersome to large marine animals, the real danger may lie in microplastics.", connotation:"negative" },
